use std::borrow::Cow;
use std::sync::OnceLock;
use wgpu::util::DeviceExt;

// The struct matches the `Params` struct in our WGSL shader.
#[repr(C)]
#[derive(Copy, Clone, Debug, bytemuck::Pod, bytemuck::Zeroable)]
pub struct TdaRenderParams {
    pub width: u32,
    pub height: u32,
    pub time: f32,
    pub betti_1: f32,
    pub active_nodes_low: u32,
    pub active_nodes_high: u32,
    pub profile_art: u32,
    pub lod: u32, // Level of detail: 0 (high) to 2 (low)
}

struct TdaContext {
    device: wgpu::Device,
    queue: wgpu::Queue,
    pipeline: wgpu::ComputePipeline,
    bind_group_layout: wgpu::BindGroupLayout,
}

// We lazily initialize the WebGPU context so it only boots once per worker.
static TDA_CONTEXT: OnceLock<TdaContext> = OnceLock::new();

fn init_wgpu_context() -> TdaContext {
    let instance = wgpu::Instance::new(wgpu::InstanceDescriptor {
        backends: wgpu::Backends::all(),
        ..Default::default()
    });

    let adapter = pollster::block_on(instance.request_adapter(&wgpu::RequestAdapterOptions {
        power_preference: wgpu::PowerPreference::HighPerformance,
        compatible_surface: None,
        force_fallback_adapter: false,
    }))
    .expect("Failed to find an appropriate WebGPU adapter");

    let (device, queue) = pollster::block_on(adapter.request_device(
        &wgpu::DeviceDescriptor {
            label: Some("TDA Render Device"),
            required_features: wgpu::Features::empty(),
            required_limits: wgpu::Limits::downlevel_defaults(),
        },
        None,
    ))
    .expect("Failed to create WebGPU device");

    let shader_src = include_str!("shaders/brain_mesh_depth.wgsl");
    let shader = device.create_shader_module(wgpu::ShaderModuleDescriptor {
        label: Some("Brain Mesh WGSL Shader"),
        source: wgpu::ShaderSource::Wgsl(Cow::Borrowed(shader_src)),
    });

    let bind_group_layout = device.create_bind_group_layout(&wgpu::BindGroupLayoutDescriptor {
        label: Some("TDA Bind Group Layout"),
        entries: &[
            wgpu::BindGroupLayoutEntry {
                binding: 0,
                visibility: wgpu::ShaderStages::COMPUTE,
                ty: wgpu::BindingType::Buffer {
                    ty: wgpu::BufferBindingType::Uniform,
                    has_dynamic_offset: false,
                    min_binding_size: None,
                },
                count: None,
            },
            wgpu::BindGroupLayoutEntry {
                binding: 1,
                visibility: wgpu::ShaderStages::COMPUTE,
                ty: wgpu::BindingType::Buffer {
                    ty: wgpu::BufferBindingType::Storage { read_only: true },
                    has_dynamic_offset: false,
                    min_binding_size: None,
                },
                count: None,
            },
            wgpu::BindGroupLayoutEntry {
                binding: 2,
                visibility: wgpu::ShaderStages::COMPUTE,
                ty: wgpu::BindingType::Buffer {
                    ty: wgpu::BufferBindingType::Storage { read_only: false },
                    has_dynamic_offset: false,
                    min_binding_size: None,
                },
                count: None,
            },
        ],
    });

    let pipeline_layout = device.create_pipeline_layout(&wgpu::PipelineLayoutDescriptor {
        label: Some("TDA Compute Pipeline Layout"),
        bind_group_layouts: &[&bind_group_layout],
        push_constant_ranges: &[],
    });

    let pipeline = device.create_compute_pipeline(&wgpu::ComputePipelineDescriptor {
        label: Some("TDA Compute Pipeline"),
        layout: Some(&pipeline_layout),
        module: &shader,
        entry_point: "main",
        compilation_options: Default::default(),
    });

    TdaContext {
        device,
        queue,
        pipeline,
        bind_group_layout,
    }
}

/// Dispatches the WGSL compute shader to render the TDA space and returns an ANSI string.
pub fn render_tda_frame(
    width: u32,
    height: u32,
    time: f32,
    betti_1: f32,
    active_mask: u64,
    adjacency_matrix: &[u64; 64],
    profile_art: bool,
    lod: u32,
) -> String {
    let ctx = TDA_CONTEXT.get_or_init(init_wgpu_context);

    let active_nodes_low = (active_mask & 0xFFFFFFFF) as u32;
    let active_nodes_high = (active_mask >> 32) as u32;

    let params = TdaRenderParams {
        width,
        height,
        time,
        betti_1,
        active_nodes_low,
        active_nodes_high,
        profile_art: if profile_art { 1 } else { 0 },
        lod,
    };

    let params_buffer = ctx
        .device
        .create_buffer_init(&wgpu::util::BufferInitDescriptor {
            label: Some("Params Uniform Buffer"),
            contents: bytemuck::bytes_of(&params),
            usage: wgpu::BufferUsages::UNIFORM | wgpu::BufferUsages::COPY_DST,
        });

    // We must pass the 64-bit matrix as an array of vec2<u32> (low, high) to match WGSL safely.
    let mut vec2_adjacency = [0u32; 128];
    for (i, &mask) in adjacency_matrix.iter().enumerate() {
        vec2_adjacency[i * 2] = (mask & 0xFFFFFFFF) as u32;
        vec2_adjacency[i * 2 + 1] = (mask >> 32) as u32;
    }

    let adjacency_buffer = ctx
        .device
        .create_buffer_init(&wgpu::util::BufferInitDescriptor {
            label: Some("Adjacency Storage Buffer"),
            contents: bytemuck::cast_slice(&vec2_adjacency),
            usage: wgpu::BufferUsages::STORAGE | wgpu::BufferUsages::COPY_DST,
        });

    let output_size = (width * height * 4) as wgpu::BufferAddress; // 1 u32 (RGBA packed) per cell
    let output_buffer = ctx.device.create_buffer(&wgpu::BufferDescriptor {
        label: Some("Output Storage Buffer"),
        size: output_size,
        usage: wgpu::BufferUsages::STORAGE | wgpu::BufferUsages::COPY_SRC,
        mapped_at_creation: false,
    });

    let readback_buffer = ctx.device.create_buffer(&wgpu::BufferDescriptor {
        label: Some("Readback Buffer"),
        size: output_size,
        usage: wgpu::BufferUsages::MAP_READ | wgpu::BufferUsages::COPY_DST,
        mapped_at_creation: false,
    });

    let bind_group = ctx.device.create_bind_group(&wgpu::BindGroupDescriptor {
        label: Some("TDA Bind Group"),
        layout: &ctx.bind_group_layout,
        entries: &[
            wgpu::BindGroupEntry {
                binding: 0,
                resource: params_buffer.as_entire_binding(),
            },
            wgpu::BindGroupEntry {
                binding: 1,
                resource: adjacency_buffer.as_entire_binding(),
            },
            wgpu::BindGroupEntry {
                binding: 2,
                resource: output_buffer.as_entire_binding(),
            },
        ],
    });

    let mut encoder = ctx
        .device
        .create_command_encoder(&wgpu::CommandEncoderDescriptor {
            label: Some("TDA Encoder"),
        });

    {
        let mut cpass = encoder.begin_compute_pass(&wgpu::ComputePassDescriptor {
            label: Some("TDA Compute Pass"),
            timestamp_writes: None,
        });
        cpass.set_pipeline(&ctx.pipeline);
        cpass.set_bind_group(0, &bind_group, &[]);

        let workgroup_x = (width + 15) / 16;
        let workgroup_y = (height + 15) / 16;
        cpass.dispatch_workgroups(workgroup_x, workgroup_y, 1);
    }

    encoder.copy_buffer_to_buffer(&output_buffer, 0, &readback_buffer, 0, output_size);

    ctx.queue.submit(Some(encoder.finish()));

    let buffer_slice = readback_buffer.slice(..);
    let (tx, rx) = std::sync::mpsc::channel();

    buffer_slice.map_async(wgpu::MapMode::Read, move |v| tx.send(v).unwrap());
    ctx.device.poll(wgpu::Maintain::Wait);
    rx.recv().unwrap().unwrap();

    let data = buffer_slice.get_mapped_range();
    let result_u32s: &[u32] = bytemuck::cast_slice(&data);

    // Now we map the RGBA buffer produced by WGSL into our ASCII terminal string.
    let mut frame_string = String::with_capacity((width * height * 12) as usize);

    // Use BRAIN_ASCII_RAMPS based on profile
    let ramp_chars: Vec<char> = if profile_art {
        " ..::ii++==**##MW@$".chars().collect()
    } else {
        " .,:;irsXA253hMHGS#9B&@".chars().collect()
    };
    let ramp_len = ramp_chars.len();

    let mut last_r = 255u8;
    let mut last_g = 255u8;
    let mut last_b = 255u8;
    let mut first_pixel = true;

    for y in 0..height {
        for x in 0..width {
            let idx = (y * width + x) as usize;
            let pixel = result_u32s[idx];

            let r = (pixel & 0xFF) as u8;
            let g = ((pixel >> 8) & 0xFF) as u8;
            let b = ((pixel >> 16) & 0xFF) as u8;

            if r == 0 && g == 0 && b == 0 {
                frame_string.push(' ');
                continue;
            }

            let luma_norm = (g as f32) / 255.0;
            let mut char_idx = (luma_norm * (ramp_len as f32)) as usize;
            if char_idx >= ramp_len {
                char_idx = ramp_len - 1;
            }
            let c = ramp_chars[char_idx];

            if first_pixel || r != last_r || g != last_g || b != last_b {
                frame_string.push_str(&format!("\x1b[38;2;{};{};{}m", r, g, b));
                last_r = r;
                last_g = g;
                last_b = b;
                first_pixel = false;
            }
            frame_string.push(c);
        }
        frame_string.push_str("\x1b[0m\n");
        first_pixel = true; // Reset color state per line to ensure line-based TTY resets work
    }

    frame_string
}
